import { Component } from "react";
import './Switch.css'

class Switch extends Component {
    render(){
        const { cambiarTema, temaOscuro } = this.props
        var opcion = '';
        opcion = (temaOscuro) => {temaOscuro
            ?   opcion = ''
            :   opcion = '-dark'
        }
        console.log(opcion)
        return (
            <div className={'contenedor-switch' + opcion}>
                <button onClick={cambiarTema} className={'switch' + opcion}>A</button>
            </div>
        )
    }
}

export default Switch
